export const proofEnrichment = Object.fromEntries(
  Object.entries({ ...entries, ...module4Entries }).map(([key, value]) => [key, {
    ...value,
    source: proofGuidesExpanded[key]?.source ?? 'Официальный список вопросов с доказательством, 05.06.2025',
  }]),
);

export function validateProofEnrichment() {
  const expected = Object.keys(proofGuidesExpanded);
  const actual = Object.keys(proofEnrichment);
  const missing = expected.filter((key) => !proofEnrichment[key]);
  const extra = actual.filter((key) => !proofGuidesExpanded[key]);
  const incomplete = expected.filter((key) => {
    const item = proofEnrichment[key];
    return !item || item.prerequisites?.length < 3 || item.annotatedSteps?.length < 4 || !item.statementLatex || !item.bigPicture || !item.symbolLegend?.length || !item.alternativeView || !item.sanityCheck || !item.oralSkeleton || !item.source;
  });
  return { expected: expected.length, covered: expected.length - missing.length, missing, extra, incomplete, complete: missing.length === 0 && extra.length === 0 && incomplete.length === 0 };
}

export const proofEnrichmentCoverage = validateProofEnrichment();
